import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useTable, useFilters, useGlobalFilter } from 'react-table';


function MaterialList() {
  const [material, setMaterial] = useState([]);
  const [newMaterialData, setNewMaterialData] = useState({
    matid: '',
    name: '',
    description: '',
    unit_of_measure: '',
    price_per_unit: 0,
    recent_vendor: '',
  });

  useEffect(() => {
    axios
      .get('http://localhost:8081')
      .then((res) => setMaterial(res.data))
      .catch((err) => console.log(err));
  }, []);

  const handleAddMaterial = () => {
    axios
      .post('http://localhost:8081', newMaterialData)
      .then((res) => {
        setMaterial((prevMaterial) => [...prevMaterial, res.data]);
        setNewMaterialData({
          matid: '',
          name: '',
          description: '',
          unit_of_measure: '',
          price_per_unit: 0,
          recent_vendor: '',
        });
      })
      .catch((err) => console.log(err));
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setNewMaterialData((prevData) => ({ ...prevData, [name]: value }));
  };

  // Define the columns for the table
  const columns = React.useMemo(
    () => [
      {
        Header: 'Material ID',
        accessor: 'matid',
      },
      {
        Header: 'Name',
        accessor: 'name',
      },
      {
        Header: 'Description',
        accessor: 'description',
      },
      {
        Header: 'Unit of Measure',
        accessor: 'unit_of_measure',
      },
      {
        Header: 'Price per Unit',
        accessor: 'price_per_unit',
      },
      {
        Header: 'Recent Vendor',
        accessor: 'recent_vendor',
      },
    ],
    []
  );

  // Create a new table instance
  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    rows,
    prepareRow,
    setGlobalFilter,
    state: { globalFilter },
  } = useTable(
    {
      columns,
      data: material,
    },
    useFilters,
    useGlobalFilter
  );

  return (
    <div>
      <div>
        <label>Search:</label>
        <input
          type="text"
          value={globalFilter || ''}
          onChange={(e) => setGlobalFilter(e.target.value)}
        />
      </div>
      <div>
        <div>
          <label>Material ID:</label>
          <input type="text" name="matid" value={newMaterialData.matid} onChange={handleInputChange} />
        </div>
        <div>
          <label>Name:</label>
          <input type="text" name="name" value={newMaterialData.name} onChange={handleInputChange} />
        </div>
        <div>
          <label>Description:</label>
          <input type="text" name="description" value={newMaterialData.description} onChange={handleInputChange} />
        </div>
        <div>
          <label>Unit of Measure:</label>
          <input type="text" name="unit_of_measure" value={newMaterialData.unit_of_measure} onChange={handleInputChange} />
        </div>
        <div>
          <label>Price per Unit:</label>
          <input type="number" name="price_per_unit" value={newMaterialData.price_per_unit} onChange={handleInputChange} />
        </div>
        <div>
          <label>Recent Vendor:</label>
          <input type="text" name="recent_vendor" value={newMaterialData.recent_vendor} onChange={handleInputChange} />
        </div>
        <button className="btn btn-success" onClick={handleAddMaterial}>Add+</button>
      </div>
      <table {...getTableProps()} className="table">
        <thead>
          {headerGroups.map((headerGroup) => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map((column) => (
                <th {...column.getHeaderProps()}>{column.render('Header')}</th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {rows.map((row) => {
            prepareRow(row);
            return (
              <tr {...row.getRowProps()}>
                {row.cells.map((cell) => (
                  <td {...cell.getCellProps()}>{cell.render('Cell')}</td>
                ))}
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

export default MaterialList;
